  1	import { type FC, type FormEvent, type Ref, type RefObject, useMemo, useState } from 'react';
  2	
  3	import {
  4	  Button,
  5	  ButtonVariant,
  6	  Chip,
  7	  ChipGroup,
  8	  MenuToggle,
  9	  type MenuToggleElement,
 10	  type MenuToggleProps,
 11	  TextInputGroup,
 12	  TextInputGroupMain,
 13	  TextInputGroupUtilities,
 14	} from '@patternfly/react-core';
 15	import { TimesIcon } from '@patternfly/react-icons';
 16	import { isEmpty } from '@utils/helpers';
 17	
 18	import type { TypeaheadSelectOption } from '../utils/types';
 19	
 20	type MultiTypeaheadMenuToggleProps = {
 21	  toggleRef: Ref<MenuToggleElement>;
 22	  inputRef: RefObject<HTMLInputElement>;
 23	  placeholder: string;
 24	  isDisabled: boolean;
 25	  isOpen: boolean;
 26	  toggleWidth?: string;
 27	  allowClear: boolean;
 28	  selectedOptions: TypeaheadSelectOption[];
 29	  isFiltering: boolean;
 30	  inputValue: string;
 31	  onInputChange?: (value: string) => void;
 32	  onClearAll: () => void;
 33	  onToggleClick: () => void;
 34	  onInputValueChange: (value: string, isFiltering: boolean) => void;
 35	  onChipRemove: (value: string | number) => void;
 36	  onInputClick: () => void;
 37	  onInputKeyDown: (e: React.KeyboardEvent<HTMLInputElement>) => void;
 38	  activeItemId: string | null;
 39	  toggleProps?: Omit<MenuToggleProps, 'innerRef' | 'onClick' | 'isExpanded' | 'variant'>;
 40	  testId?: string;
 41	  listboxId: string; // for aria-controls
 42	};
 43	
 44	const MultiTypeaheadMenuToggle: FC<MultiTypeaheadMenuToggleProps> = ({
 45	  activeItemId,
 46	  allowClear,
 47	  inputRef,
 48	  inputValue,
 49	  isDisabled,
 50	  isFiltering,
 51	  isOpen,
 52	  listboxId,
 53	  onChipRemove,
 54	  onClearAll,
 55	  onInputChange,
 56	  onInputClick,
 57	  onInputKeyDown,
 58	  onInputValueChange,
 59	  onToggleClick,
 60	  placeholder,
 61	  selectedOptions,
 62	  testId,
 63	  toggleProps,
 64	  toggleRef,
 65	  toggleWidth,
 66	}) => {
 67	  const [isFocused, setIsFocused] = useState(false);
 68	  const [isHovered, setIsHovered] = useState(false);
 69	
 70	  const showClearButton = useMemo(() => {
 71	    const hasAnySelection = !isEmpty(selectedOptions);
 72	    const hasTypedValue = isFiltering && !isEmpty(inputValue);
 73	    return (
 74	      allowClear && (hasAnySelection || hasTypedValue) && (isFocused || isHovered || isFiltering)
 75	    );
 76	  }, [allowClear, selectedOptions, isFiltering, inputValue, isFocused, isHovered]);
 77	
 78	  const handleToggleClick = (): void => {
 79	    if (isDisabled) return;
 80	    onToggleClick();
 81	    if (!isOpen) setTimeout(() => inputRef.current?.focus(), 0);
 82	  };
 83	
 84	  const handleInputChange = (event: FormEvent<HTMLInputElement>, newValue: string): void => {
 85	    if (isDisabled) return;
 86	    onInputValueChange(newValue, true);
 87	    onInputChange?.(newValue);
 88	
 89	    if (!isDisabled && !isOpen && !isEmpty(newValue)) {
 90	      onToggleClick();
 91	    }
 92	  };
 93	
 94	  const handleKeyDown: React.KeyboardEventHandler<HTMLInputElement> = (e) => {
 95	    onInputKeyDown(e);
 96	    // Backspace removes last chip when input is empty
 97	    if (e.key === 'Backspace' && !inputValue && !isEmpty(selectedOptions)) {
 98	      e.preventDefault();
 99	      const last = selectedOptions[selectedOptions.length - 1];
100	      onChipRemove(last.value);
101	    }
102	  };
103	
104	  return (
105	    <MenuToggle
106	      variant="typeahead"
107	      aria-label="Multi typeahead creatable menu toggle"
108	      onClick={handleToggleClick}
109	      innerRef={toggleRef}
110	      isExpanded={isOpen}
111	      isDisabled={isDisabled}
112	      isFullWidth
113	      style={{ width: toggleWidth }}
114	      onMouseEnter={() => {
115	        setIsHovered(true);
116	      }}
117	      onMouseLeave={() => {
118	        setIsHovered(false);
119	      }}
120	      data-testid={testId}
121	      {...toggleProps}
122	    >
123	      <TextInputGroup isPlain>
124	        <TextInputGroupMain
125	          value={inputValue}
126	          onClick={onInputClick}
127	          onChange={handleInputChange}
128	          onKeyDown={handleKeyDown}
129	          autoComplete="off"
130	          innerRef={inputRef}
131	          placeholder={placeholder}
132	          {...(activeItemId ? { 'aria-activedescendant': activeItemId } : {})}
133	          role="combobox"
134	          isExpanded={isOpen}
135	          aria-controls={listboxId}
136	          onFocus={() => {
137	            setIsFocused(true);
138	          }}
139	          onBlur={() => {
140	            setIsFocused(false);
141	          }}
142	        >
143	          <ChipGroup aria-label="Current selections">
144	            {selectedOptions.map((opt) => (
145	              <Chip
146	                key={String(opt.value)}
147	                onClick={(ev) => {
148	                  ev.stopPropagation();
149	                  onChipRemove(opt.value);
150	                }}
151	              >
152	                {opt.content}
153	              </Chip>
154	            ))}
155	          </ChipGroup>
156	        </TextInputGroupMain>
157	
158	        <TextInputGroupUtilities
159	          {...(isEmpty(selectedOptions) ? { style: { display: 'none' } } : {})}
160	        >
161	          {showClearButton && (
162	            <Button
163	              icon={<TimesIcon />}
164	              variant={ButtonVariant.plain}
165	              onClick={() => {
166	                onInputValueChange('', false);
167	                onClearAll();
168	                inputRef.current?.focus();
169	              }}
170	              aria-label="Clear selections"
171	            />
172	          )}
173	        </TextInputGroupUtilities>
174	      </TextInputGroup>
175	    </MenuToggle>
176	  );
177	};
178	
179	export default MultiTypeaheadMenuToggle;

