150	                  onChipRemove(opt.value);
151	                }}
152	              >
153	                {opt.content}
154	              </Label>
155	            ))}
156	          </LabelGroup>
157	        </TextInputGroupMain>
158	
159	        <TextInputGroupUtilities
160	          {...(isEmpty(selectedOptions) ? { style: { display: 'none' } } : {})}
